import{_ as a,o,c as t,ag as i}from"./chunks/framework.PErH1-Uo.js";const m=JSON.parse('{"title":"Guía Técnica: Servicios Linux y Gestión de OpenLDAP","description":"","frontmatter":{},"headers":[],"relativePath":"linux/_hidden/OpenLDAP/comandos.md","filePath":"linux/_hidden/OpenLDAP/comandos.md","lastUpdated":1775578468000}'),d={name:"linux/_hidden/OpenLDAP/comandos.md"};function s(r,e,n,c,l,u){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="guia-tecnica-servicios-linux-y-gestion-de-openldap" tabindex="-1">Guía Técnica: Servicios Linux y Gestión de OpenLDAP <a class="header-anchor" href="#guia-tecnica-servicios-linux-y-gestion-de-openldap" aria-label="Permalink to &quot;Guía Técnica: Servicios Linux y Gestión de OpenLDAP&quot;">​</a></h1><p>Esta guía unifica los comandos esenciales para administrar servicios en el sistema operativo y gestionar un directorio LDAP.</p><hr><h2 id="🐧-parte-1-ver-servicios-en-ejecucion-en-linux" tabindex="-1">🐧 PARTE 1: Ver Servicios en Ejecución en Linux <a class="header-anchor" href="#🐧-parte-1-ver-servicios-en-ejecucion-en-linux" aria-label="Permalink to &quot;🐧 PARTE 1: Ver Servicios en Ejecución en Linux&quot;">​</a></h2><p>La forma de ver los servicios depende del sistema de inicio de tu distribución.</p><h3 id="_1-sistema-systemd-ubuntu-15-04-debian-8-centos-7" tabindex="-1">1. Sistema Systemd (Ubuntu 15.04+, Debian 8+, CentOS 7+) <a class="header-anchor" href="#_1-sistema-systemd-ubuntu-15-04-debian-8-centos-7" aria-label="Permalink to &quot;1. Sistema Systemd (Ubuntu 15.04+, Debian 8+, CentOS 7+)&quot;">​</a></h3><p>Es el estándar actual en casi todas las distros modernas.</p><ul><li><strong>Listar solo servicios activos:</strong><code>systemctl list-units --type=service --state=running</code></li><li><strong>Ver el estado de un servicio específico:</strong><code>systemctl status &lt;nombre_del_servicio&gt;</code></li><li><strong>Listar todos los servicios (activos e inactivos):</strong><code>systemctl list-unit-files --type=service</code></li></ul><h3 id="_2-sistemas-antiguos-sysvinit-upstart" tabindex="-1">2. Sistemas Antiguos (SysVinit / Upstart) <a class="header-anchor" href="#_2-sistemas-antiguos-sysvinit-upstart" aria-label="Permalink to &quot;2. Sistemas Antiguos (SysVinit / Upstart)&quot;">​</a></h3><ul><li><strong>Comprobar todos los servicios:</strong><code>service --status-all</code></li><li><strong>Listar servicios en Upstart:</strong><code>initctl list</code></li></ul><h3 id="_3-comandos-universales-procesos" tabindex="-1">3. Comandos Universales (Procesos) <a class="header-anchor" href="#_3-comandos-universales-procesos" aria-label="Permalink to &quot;3. Comandos Universales (Procesos)&quot;">​</a></h3><p>Si quieres ver qué está corriendo sin importar el gestor:</p><ul><li><code>top</code> o <code>htop</code> (interactivo).</li><li><code>ps aux</code> (lista estática de procesos).</li></ul><hr><h2 id="🌳-parte-2-gestion-de-openldap" tabindex="-1">🌳 PARTE 2: Gestión de OpenLDAP <a class="header-anchor" href="#🌳-parte-2-gestion-de-openldap" aria-label="Permalink to &quot;🌳 PARTE 2: Gestión de OpenLDAP&quot;">​</a></h2><p>LDAP organiza la información en un árbol jerárquico. Para interactuar con él, usamos los siguientes comandos:</p><h3 id="_1-la-regla-de-oro-de-los-parametros" tabindex="-1">1. La &quot;Regla de Oro&quot; de los Parámetros <a class="header-anchor" href="#_1-la-regla-de-oro-de-los-parametros" aria-label="Permalink to &quot;1. La &quot;Regla de Oro&quot; de los Parámetros&quot;">​</a></h3><p>Antes de ejecutar cualquier comando, recuerda estos modificadores básicos:</p><ul><li><strong><code>-x</code></strong>: Autenticación simple (en lugar de SASL).</li><li><strong><code>-H &lt;uri&gt;</code></strong>: Dirección del servidor (ej. <code>ldap://localhost</code>).</li><li><strong><code>-D &lt;binddn&gt;</code></strong>: DN del administrador (ej. <code>&quot;cn=admin,dc=dominio,dc=com&quot;</code>).</li><li><strong><code>-W</code></strong>: Solicita la contraseña de forma interactiva (seguridad recomendada).</li><li><strong><code>-b &lt;base&gt;</code></strong>: Punto de partida de la búsqueda (Base DN).</li></ul><h2 id="_2-lectura-y-busqueda-ldapsearch" tabindex="-1">2. Lectura y Búsqueda: <code>ldapsearch</code> <a class="header-anchor" href="#_2-lectura-y-busqueda-ldapsearch" aria-label="Permalink to &quot;2\\. Lectura y Búsqueda: `ldapsearch`&quot;">​</a></h2><p>Es la herramienta para consultar el árbol de directorios (DIT).</p><ul><li><p><strong>Listar todo el árbol:</strong></p><pre><code>ldapsearch -x -b &quot;dc=ejemplo,dc=com&quot; -H ldap://localhost\n</code></pre></li><li><p><strong>Buscar un usuario por su UID:</strong></p><pre><code>ldapsearch -x -b &quot;dc=ejemplo,dc=com&quot; &quot;(uid=jdoe)&quot;\n</code></pre></li><li><p><strong>Ver solo atributos específicos (Nombre y Mail):</strong></p><pre><code>ldapsearch -x -b &quot;dc=ejemplo,dc=com&quot; &quot;(uid=*)&quot; cn mail\n</code></pre></li></ul><hr><h2 id="_3-escritura-y-modificacion-uso-de-archivos-ldif" tabindex="-1">3. Escritura y Modificación (Uso de archivos <code>.ldif</code>) <a class="header-anchor" href="#_3-escritura-y-modificacion-uso-de-archivos-ldif" aria-label="Permalink to &quot;3\\. Escritura y Modificación (Uso de archivos `.ldif`)&quot;">​</a></h2><p>LDAP no suele editarse &quot;en vivo&quot; por línea de comandos; se recomienda usar archivos de texto con formato <strong>LDIF</strong>.</p><h3 id="➕-anadir-objetos-ldapadd" tabindex="-1">➕ Añadir objetos (<code>ldapadd</code>) <a class="header-anchor" href="#➕-anadir-objetos-ldapadd" aria-label="Permalink to &quot;➕ Añadir objetos (`ldapadd`)&quot;">​</a></h3><pre><code>ldapadd -x -D &quot;cn=admin,dc=com&quot; -W -f nuevo_usuario.ldif\n</code></pre><h3 id="✏️-modificar-objetos-ldapmodify" tabindex="-1">✏️ Modificar objetos (<code>ldapmodify</code>) <a class="header-anchor" href="#✏️-modificar-objetos-ldapmodify" aria-label="Permalink to &quot;✏️ Modificar objetos (`ldapmodify`)&quot;">​</a></h3><p>Se usa para cambiar, añadir o eliminar atributos de un registro existente.</p><pre><code>ldapmodify -x -D &quot;cn=admin,dc=com&quot; -W -f cambios.ldif\n</code></pre><h3 id="🗑️-eliminar-objetos-ldapdelete" tabindex="-1">🗑️ Eliminar objetos (<code>ldapdelete</code>) <a class="header-anchor" href="#🗑️-eliminar-objetos-ldapdelete" aria-label="Permalink to &quot;🗑️ Eliminar objetos (`ldapdelete`)&quot;">​</a></h3><p>Requiere el Distinguished Name (DN) completo:</p><pre><code>ldapdelete -x -D &quot;cn=admin,dc=com&quot; -W &quot;uid=jdoe,ou=users,dc=com&quot;\n</code></pre><hr><h2 id="_4-mantenimiento-y-contrasenas" tabindex="-1">4. Mantenimiento y Contraseñas <a class="header-anchor" href="#_4-mantenimiento-y-contrasenas" aria-label="Permalink to &quot;4\\. Mantenimiento y Contraseñas&quot;">​</a></h2><ul><li><p><strong>Cambiar contraseña (<code>ldappasswd</code>):</strong></p><pre><code>ldappasswd -x -D &quot;cn=admin,dc=com&quot; -W -S &quot;uid=jdoe,ou=users,dc=com&quot;\n</code></pre></li><li><p><strong>Exportar Backup (<code>slapcat</code>):</strong> <em>Ejecutar como root directamente en el servidor.</em></p><pre><code>sudo slapcat -l backup_$(date +%F).ldif\n</code></pre></li><li><p><strong>Validar Configuración (<code>slaptest</code>):</strong></p><pre><code>sudo slaptest -u\n</code></pre></li></ul><hr><hr><h2 id="📋-resumen-de-comandos-rapidos" tabindex="-1">📋 Resumen de Comandos Rápidos <a class="header-anchor" href="#📋-resumen-de-comandos-rapidos" aria-label="Permalink to &quot;📋 Resumen de Comandos Rápidos&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Acción</th><th>Comando</th><th>Descripción</th></tr></thead><tbody><tr><td>Consultar</td><td>ldapsearch</td><td>Busca y visualiza objetos en el DIT.</td></tr><tr><td>Insertar</td><td>ldapadd</td><td>Añade entradas desde un fichero LDIF.</td></tr><tr><td>Modificar</td><td>ldapmodify</td><td>Aplica cambios a entradas existentes.</td></tr><tr><td>Eliminar</td><td>ldapdelete</td><td>Borra una entrada específica.</td></tr><tr><td>Password</td><td>ldappasswd</td><td>Cambia la clave de un usuario.</td></tr><tr><td>Backup</td><td>slapcat</td><td>Vuelca la base de datos a texto plano.</td></tr></tbody></table>',40)])])}const h=a(d,[["render",s]]);export{m as __pageData,h as default};
